USE BD_Nincoming

DECLARE @PROV AS varchar(10); SET @PROV = 'DYS6';
DECLARE @SUP INT; SET @SUP = 2;

DECLARE @WYNDHAM TABLE (HOTELS VARCHAR(10));
DECLARE @ACTIVE_WYNDHAM_MONGO TABLE (HOTELS VARCHAR(10));

DECLARE @ALOJA_PUSH TABLE (HOTELS VARCHAR(10));
DECLARE @DERBY_PUSH TABLE (HOTELS VARCHAR(10));
DECLARE @NO_DERBY_PUSH TABLE (HOTELS VARCHAR(10));
DECLARE @WYNDHAM_PUSH TABLE (HOTELS VARCHAR(10));
DECLARE @DERBY_NO_WYNDHAM_PUSH TABLE (HOTELS VARCHAR(10));
DECLARE @ACTIVE_WYNDHAM TABLE (HOTELS VARCHAR(10));
DECLARE @INACTIVE_WYNDHAM TABLE (HOTELS VARCHAR(10));

DECLARE @CODHOTELS TABLE (HOTELS VARCHAR(10));
DECLARE @CODRATES TABLE (RATES VARCHAR(10));
DECLARE @ELEMENTS TABLE (ID_ELEMENT INT);
DECLARE @ELEMENTS_ACTIVE TABLE (ID_ELEMENT INT);
DECLARE @ELEMENTS_HOTELS_INACTIVE TABLE (ID_ELEMENT INT);
DECLARE @ELEMENTS_PRODUCTS_INACTIVE TABLE (ID_ELEMENT INT);


DECLARE @COUNTELEMENTS TABLE (ELEMENTO VARCHAR(MAX),NUM_ELEMENT INT);

-----------FICHAS-----------
INSERT INTO @WYNDHAM
	SELECT DISTINCT(AlE_Cod) 
	FROM vwQlik_JP_Externos 
	WHERE AlE_Prov = @PROV
