--INSERT INTO @ALOJA_PUSH
--	SELECT DISTINCT(SPE_CodHotel)
--	FROM Tbl_AlojaSupplierPushElemento 
----SELECT COUNT(*) AS [ALOJA_PUSH] FROM @ALOJA_PUSH

INSERT INTO @DERBY_PUSH
	SELECT DISTINCT(SPE_CodHotel)
	FROM Tbl_AlojaSupplierPushElemento 
	WHERE Id_SuP = @SUP 
